using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record PredictRequest(string Subject, string Description, int Priority);

public record PredictResponse(string Category, Dictionary<string, float> Confidence);

public record EvaluationResponse(
    double MacroAccuracy,
    double MicroAccuracy,
    double LogLoss,
    double LogLossReduction,
    IReadOnlyList<CategoryMetric> PerCategory);

public record CategoryMetric(string Category, double Precision, double Recall, double F1Score);

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly IDataView _trainingData;
    private readonly string[] _categoryNames;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);
        _trainingData = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(_trainingData);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract the ordered label names from the trained model's key-value mapping
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        _model.GetOutputSchema(_trainingData.Schema)["PredictedLabel"]
            .GetKeyValues(ref labelBuffer);
        _categoryNames = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
    }

    public PredictResponse Predict(PredictRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categoryNames.Length; i++)
        {
            confidence[_categoryNames[i]] = prediction.Score[i];
        }

        return new PredictResponse(prediction.PredictedCategory, confidence);
    }

    public EvaluationResponse Evaluate()
    {
        // Cross-validate with the full dataset to get meaningful metrics from small data
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(
            _trainingData, BuildPipeline(), numberOfFolds: 3);

        var avgMetrics = new
        {
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction)
        };

        // Also evaluate the final trained model on training data for per-class metrics
        var predictions = _model.Transform(_trainingData);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        var perCategory = metrics.PerClassLogLoss
            .Select((logLoss, i) => new CategoryMetric(
                _categoryNames.ElementAtOrDefault(i) ?? $"Class{i}",
                Precision: i < _categoryNames.Length ? ComputePerClass(predictions, i).Precision : 0,
                Recall: i < _categoryNames.Length ? ComputePerClass(predictions, i).Recall : 0,
                F1Score: i < _categoryNames.Length ? ComputePerClass(predictions, i).F1 : 0))
            .ToList();

        return new EvaluationResponse(
            Math.Round(avgMetrics.MacroAccuracy, 4),
            Math.Round(avgMetrics.MicroAccuracy, 4),
            Math.Round(avgMetrics.LogLoss, 4),
            Math.Round(avgMetrics.LogLossReduction, 4),
            perCategory);
    }

    private (double Precision, double Recall, double F1) ComputePerClass(IDataView predictions, int classIndex)
    {
        var predicted = _mlContext.Data.CreateEnumerable<TicketPrediction>(predictions, reuseRowObject: false).ToList();
        var actual = _mlContext.Data.CreateEnumerable<TicketData>(predictions, reuseRowObject: false).ToList();

        var className = _categoryNames[classIndex];
        int tp = 0, fp = 0, fn = 0;
        for (var i = 0; i < actual.Count; i++)
        {
            var isPredicted = predicted[i].PredictedCategory == className;
            var isActual = actual[i].Category == className;
            if (isPredicted && isActual) tp++;
            else if (isPredicted) fp++;
            else if (isActual) fn++;
        }

        var precision = tp + fp > 0 ? (double)tp / (tp + fp) : 0;
        var recall = tp + fn > 0 ? (double)tp / (tp + fn) : 0;
        var f1 = precision + recall > 0 ? 2 * precision * recall / (precision + recall) : 0;
        return (Math.Round(precision, 4), Math.Round(recall, 4), Math.Round(f1, 4));
    }

    private IEstimator<ITransformer> BuildPipeline()
    {
        return _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("predict")]
    public ActionResult<PredictResponse> Predict([FromBody] PredictRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject))
            return BadRequest("Subject is required.");

        if (string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationResponse> GetMetrics()
    {
        var metrics = _classifier.Evaluate();
        return Ok(metrics);
    }
}

