arguments.new_str:
public EvaluationResponse Evaluate()
{
    // Evaluate the trained model on training data for metrics
    var predictions = _model.Transform(_trainingData);
    var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

    var perCategory = _categoryNames
        .Select((name, i) =>
        {
            var stats = ComputePerClass(predictions, i);
            return new CategoryMetric(name, stats.Precision, stats.Recall, stats.F1);
        })
        .ToList();

    return new EvaluationResponse(
        SafeRound(metrics.MacroAccuracy),
        SafeRound(metrics.MicroAccuracy),
        SafeRound(metrics.LogLoss),
        SafeRound(metrics.LogLossReduction),
        perCategory);
}

private static double SafeRound(double value)
{
    if (double.IsNaN(value) || double.IsInfinity(value))
        return 0;
    return Math.Round(value, 4);
}

